const auth = $('인증 확인').item.json.result;
const body = $('Webhook').item.json.body;

if (!auth.success) {
  return [{ json: { authorized: false, message: auth.message || '인증 실패' } }];
}

if (auth.tokens_remaining <= 0 && !['super_admin','company_admin'].includes(auth.role)) {
  return [{ json: { authorized: false, message: '토큰이 소진되었습니다. 관리자에게 문의하세요.' } }];
}

// 요청한 카테고리 필터링 (빈 배열 = 전체)
const requestedCats = body.categories || []; // 카테고리 이름 배열
const allCats = auth.categories || [];

let targetTables;
if (requestedCats.length === 0) {
  // 전체: 접근 가능한 모든 테이블
  targetTables = allCats.map(c => ({ table: c.table_name, name: c.name }));
} else {
  // 선택한 카테고리만
  targetTables = allCats
    .filter(c => requestedCats.includes(c.name))
    .map(c => ({ table: c.table_name, name: c.name }));
}

if (targetTables.length === 0) {
  return [{ json: { authorized: false, message: '접근 가능한 카테고리가 없습니다' } }];
}

return [{ json: {
  authorized: true,
  userId: auth.id,
  companyId: auth.company_id,
  message: body.message,
  sessionId: body.session_id || 'session-' + Date.now(),
  targetTables
} }];

// 각 카테고리 테이블에서 유사 문서 검색
const embedding = $input.first().json.data[0].embedding;
const authData = $('인증 & 파싱').item.json;
const tables = authData.targetTables;

// Supabase RPC 쿼리 생성 (여러 테이블 UNION)
const queries = tables.map(t =>
  `SELECT content, metadata, 1 - (embedding <=> '${JSON.stringify(embedding)}'::vector) AS similarity, '${t.name}' AS category_name FROM ${t.table} WHERE 1 - (embedding <=> '${JSON.stringify(embedding)}'::vector) > 0.5 ORDER BY embedding <=> '${JSON.stringify(embedding)}'::vector LIMIT 3`
).join(' UNION ALL ');

const finalQuery = `SELECT * FROM (${queries}) AS combined ORDER BY similarity DESC LIMIT 8`;

return [{ json: {
  query: finalQuery,
  message: authData.message,
  userId: authData.userId,
  sessionId: authData.sessionId
} }];

// 검색 결과로 컨텍스트 구성
const docs = $input.all().map(i => i.json);
const prevData = $('검색 쿼리 생성').item.json;

// 소스 정보 추출
const sources = docs.map(d => ({
  filename: d.metadata?.source_filename || '알 수 없는 파일',
  similarity: d.similarity || 0,
  category_name: d.category_name || '',
  drive_url: d.metadata?.source_drive_url || null
}));

// RAG 컨텍스트 구성
const context = docs.length > 0
  ? docs.map((d, i) => `[문서 ${i+1}] (${d.category_name})\n${d.content}`).join('\n\n')
  : '관련 내부 문서를 찾지 못했습니다.';

return [{ json: {
  context,
  sources,
  message: prevData.message,
  userId: prevData.userId,
  sessionId: prevData.sessionId,
  hasContext: docs.length > 0
} }];

