const gptResponse = $('GPT-4.1 답변 생성').item.json;
const tokenResult = $input.first().json.result;
const ctxData = $('컨텍스트 구성').item.json;

const answer = gptResponse.choices?.[0]?.message?.content || '답변을 생성하지 못했습니다.';

return [{ json: {
  success: true,
  response: answer,
  tokens_remaining: tokenResult.tokens_remaining || 0,
  sources: ctxData.sources || []
} }];
